import{_ as e,o as a,c as o,ag as s}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"规则编写","description":"","frontmatter":{},"headers":[],"relativePath":"zh/settings/rule-authoring.md","filePath":"zh/settings/rule-authoring.md","lastUpdated":1782658073000}'),i={name:"zh/settings/rule-authoring.md"};function d(l,t,r,n,c,h){return a(),o("div",null,[...t[0]||(t[0]=[s(`<h1 id="规则编写" tabindex="-1">规则编写 <a class="header-anchor" href="#规则编写" aria-label="Permalink to &quot;规则编写&quot;">​</a></h1><p>EasyApi 开箱即用地支持标准 HTTP 框架（Spring MVC、WebFlux、JAX-RS、Feign）—— <strong>大多数项目无需自定义规则</strong>。对于扫描器无法察觉的自定义框架行为（例如要求添加请求头的 <code>jakarta.servlet.Filter</code>，或将每个响应包装在信封中的 <code>ResponseBodyAdvice</code>），可使用内置的 AI 助手或外部 skill 来检测并生成规则。完整的自定义模式目录请参见 <a href="https://github.com/tangcent/easy-yapi/blob/master/docs/knowledge-base/rule-guide.md" target="_blank" rel="noreferrer">Rule Authoring Guide</a>。</p><p>本页介绍 EasyYapi 3.x 中编写规则的<strong>三种方式</strong>，请根据你的工作流选择。</p><table tabindex="0"><thead><tr><th>方式</th><th>适用场景</th><th>位置</th></tr></thead><tbody><tr><td><a href="#基于文件夹的规则文件">基于文件夹的规则文件</a></td><td>希望以纯文本方式纳入版本控制的团队</td><td><code>.easyapi/*.rules</code></td></tr><tr><td><a href="#内置-ai-助手">内置 AI 助手</a></td><td>快速编写单条规则，或扫描项目中隐藏的框架行为</td><td>Settings → EasyApi → Rules → Chat / Magic</td></tr><tr><td><a href="#外部-easy-yapi-assistant-skill">外部 <code>easy-yapi-assistant</code> skill</a></td><td>通过外部 AI 工具（CLI / IDE agent）驱动规则编写</td><td>已随插件打包</td></tr></tbody></table><hr><h2 id="基于文件夹的规则文件" tabindex="-1">基于文件夹的规则文件 <a class="header-anchor" href="#基于文件夹的规则文件" aria-label="Permalink to &quot;基于文件夹的规则文件&quot;">​</a></h2><p>从 EasyYapi 3.0 起，规则文件按<strong>文件夹</strong>自动发现，取代了旧的单 <code>.easy.api.config</code> 文件工作流（旧文件仍会被读取以保持向后兼容）。</p><h3 id="规则文件位置" tabindex="-1">规则文件位置 <a class="header-anchor" href="#规则文件位置" aria-label="Permalink to &quot;规则文件位置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>范围</th><th>文件夹</th><th>作用于</th></tr></thead><tbody><tr><td><strong>项目</strong></td><td><code>&lt;project&gt;/.easyapi/*.rules</code>（或 <code>*.properties</code>）</td><td>仅当前项目</td></tr><tr><td><strong>全局</strong></td><td><code>~/.easyapi/*.rules</code></td><td>本机所有项目</td></tr><tr><td><strong>内置</strong></td><td>随插件打包</td><td>始终加载</td></tr><tr><td><strong>远程</strong></td><td>在 Settings → Remote 中配置的 URL</td><td>重新加载时拉取</td></tr></tbody></table><p>文件夹中的每个常规文件都会被自动加载——无需维护文件列表。文件夹是唯一的真相来源。</p><h3 id="文件格式" tabindex="-1">文件格式 <a class="header-anchor" href="#文件格式" aria-label="Permalink to &quot;文件格式&quot;">​</a></h3><p>规则文件是 UTF-8 文本文件，每行一条规则：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 格式: &lt;key&gt;[&lt;filter&gt;]=&lt;value&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   key      — 规则键（参见 可用配置规则）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   filter   — 可选；放在 key 之后的 [...] 中</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   value    — 字面文本、表达式或 Groovy 脚本</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 没有过滤器的规则对所有元素生效：</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">api.status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=disabled</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 带过滤器的规则只对匹配元素生效：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">api.tag[$class:com.example.UserController]=user</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Groovy 脚本以 &quot;groovy:&quot; 前缀标识：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">field.ignore[groovy: it.name() == </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;internalCache&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]=true</span></span></code></pre></div><h3 id="在-ide-中管理文件" tabindex="-1">在 IDE 中管理文件 <a class="header-anchor" href="#在-ide-中管理文件" aria-label="Permalink to &quot;在 IDE 中管理文件&quot;">​</a></h3><p>打开 <strong>Settings → EasyApi → Rules</strong>。该标签页包含三个子标签——<strong>Project</strong>、<strong>Global</strong>、<strong>Remote</strong>：</p><ul><li>可直接在对话框中添加 / 编辑 / 重命名 / 删除文件。</li><li>取消文件旁的 <strong>Enabled</strong> 复选框可在不删除文件的情况下禁用它。被禁用的路径保存在 <code>Settings.disabledAutoRuleFiles</code>（项目级）或 <code>Settings.disabledGlobalRuleFiles</code>（全局级）中。</li><li>保存即重新加载，无需重启 IDE。</li></ul><h3 id="过滤器语法速查" tabindex="-1">过滤器语法速查 <a class="header-anchor" href="#过滤器语法速查" aria-label="Permalink to &quot;过滤器语法速查&quot;">​</a></h3><p>过滤器位于 key 之后的 <code>[...]</code> 中，限制规则只对匹配的元素生效：</p><table tabindex="0"><thead><tr><th>前缀</th><th>含义</th><th>示例</th></tr></thead><tbody><tr><td><code>$class:</code></td><td>全限定类名精确匹配</td><td><code>$class:com.example.UserController</code></td></tr><tr><td><code>@</code></td><td>匹配带有指定注解的元素</td><td><code>@org.springframework.web.bind.annotation.RestController</code></td></tr><tr><td><code>#regex:</code></td><td>正则匹配；捕获组可用 <code>\${1}</code>、<code>\${2}</code></td><td><code>#regex:Mono&lt;(.*?)&gt;</code></td></tr><tr><td><code>#</code></td><td>标签匹配（来自注释或注解）</td><td><code>#internal</code></td></tr><tr><td><code>!</code></td><td>对后续表达式取反</td><td><code>!@java.lang.Deprecated</code></td></tr><tr><td><code>groovy:</code></td><td>返回真值的 Groovy 脚本</td><td><code>groovy: it.hasAnn(&quot;X&quot;)</code></td></tr><tr><td><em>(无)</em></td><td>字面值，总是匹配</td><td><code>api.status=disabled</code></td></tr></tbody></table><blockquote><p><strong>迁移提示：</strong> 2.x 中的 <code>class:com.example.Foo</code> 与 <code>~regex</code> 形式在 3.x 中无效。请改用 <code>$class:</code>（精确匹配）或 <code>groovy:</code>（模式匹配）。完整规则键目录参见 <a href="./config-rule">可用配置规则</a>。</p></blockquote><hr><h2 id="内置-ai-助手" tabindex="-1">内置 AI 助手 <a class="header-anchor" href="#内置-ai-助手" aria-label="Permalink to &quot;内置 AI 助手&quot;">​</a></h2><p>EasyYapi 3.0 内置了与供应商无关的 AI 助手，可用自然语言为你编写规则。它集成在 Rules 标签页中，使用与外部 skill 相同的知识库。</p><h3 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h3><ol><li>打开 <strong>Settings → EasyApi → AI</strong>（独立的顶级标签页）。</li><li>选择供应商（<code>OPENAI</code>、<code>ANTHROPIC</code>、<code>GEMINI</code>、<code>OLLAMA</code>、<code>AZURE_OPENAI</code> 或 <code>CUSTOM</code>）。</li><li>输入 API key（安全存储在 IntelliJ 的 <code>PasswordSafe</code> 中）、base URL（已知供应商会自动填充）和模型名。</li><li>点击 <strong>Test Connection</strong> 验证。该测试使用界面上的字段值，因此可在点击 Apply/OK 之前先验证。</li><li>点击 <strong>Auto-detect</strong> 让 EasyYapi 从环境变量（<code>OPENAI_API_KEY</code>、<code>ANTHROPIC_API_KEY</code>、<code>OLLAMA_HOST</code> 等）推断供应商。</li></ol><h3 id="工作流" tabindex="-1">工作流 <a class="header-anchor" href="#工作流" aria-label="Permalink to &quot;工作流&quot;">​</a></h3><ol><li>打开 <strong>Settings → EasyApi → Rules</strong>。</li><li>点击底部操作栏的 <strong>Chat</strong> 打开内嵌 AI 面板，或点击 <strong>Magic</strong> 运行内置的&quot;审查并检测&quot;指令。</li><li>用自然语言输入请求，例如： <ul><li>&quot;将 <code>UserController</code> 中所有端点重命名为以 <code>fetch_</code> 开头。&quot;</li><li>&quot;为 <code>internal</code> 包中所有类添加 <code>internal</code> 标签。&quot;</li><li>&quot;检测需要请求头的自定义 Filter 并为我生成规则。&quot;</li></ul></li><li>助手会读取你现有的规则、推理你的请求，并提出规则内容。</li><li>在提案卡片中审阅，可在保存前 <strong>Edit</strong> 内容。</li><li>点击 <strong>Save…</strong>——选择 Global（<code>~/.easyapi/</code>）或 Project（<code>&lt;project&gt;/.easyapi/</code>）范围及文件名。</li><li>规则文件写入所选文件夹，配置立即重新加载。</li></ol><p>助手<strong>永远不会在未经你明确批准的情况下写文件</strong>——每个会改变状态的动作工具都需要点击 Approve。</p><h3 id="magic-按钮" tabindex="-1">Magic 按钮 <a class="header-anchor" href="#magic-按钮" aria-label="Permalink to &quot;Magic 按钮&quot;">​</a></h3><p><strong>Magic</strong> 会运行一条内置指令，用于：</p><ol><li>审查现有规则的缺口。</li><li>扫描项目中缺少规则的自定义框架模式（Filter、Interceptor、<code>ResponseBodyAdvice</code>、<code>HandlerMethodArgumentResolver</code>、元注解）。</li><li>依据 <a href="https://github.com/tangcent/easy-yapi/blob/master/docs/knowledge-base/rule-guide.md#custom-pattern-catalog" target="_blank" rel="noreferrer">Custom-Pattern Catalog</a> 为每个检测结果提出规则。</li></ol><hr><h2 id="外部-easy-yapi-assistant-skill" tabindex="-1">外部 <code>easy-yapi-assistant</code> skill <a class="header-anchor" href="#外部-easy-yapi-assistant-skill" aria-label="Permalink to &quot;外部 \`easy-yapi-assistant\` skill&quot;">​</a></h2><p>对于希望通过外部 AI 工具（CLI agent、IDE 助手、CI 辅助）驱动规则编写的团队，EasyYapi 打包了 <code>easy-yapi-assistant</code> skill。该 skill 随插件发布，使用与内置助手相同的知识库，确保外部工具与内置助手始终从同一真相来源编写规则。</p><p>该 skill 提供：</p><ul><li><strong>Rule-key catalog</strong> — 受支持规则键的权威清单。</li><li><strong>Custom-Pattern Catalog</strong> — 与 Magic 按钮相同的检测模式。</li><li><strong>辅助脚本</strong> — <code>list_rule_files.sh</code>、<code>read_rule_file.sh</code>、<code>get_existing_rules_for_key.sh</code>，用于检查 <code>.easyapi/</code> 文件夹中的现有规则。</li></ul><p>适用于以下场景：</p><ul><li>通过终端 AI 工具编写规则。</li><li>在 CI 中跨多个仓库批量检测自定义框架行为。</li><li>生成规则草稿，再由人工在 IDE 中最终确认。</li></ul><hr><h2 id="_3-1-x-新特性" tabindex="-1">3.1.x 新特性 <a class="header-anchor" href="#_3-1-x-新特性" aria-label="Permalink to &quot;3.1.x 新特性&quot;">​</a></h2><p>近期值得了解的变更：</p><ul><li><strong>基于文件夹的规则管理</strong> (<code>#1398</code>)——项目级和全局级的 <code>.easyapi/*.rules</code> 文件夹模型，取代旧的单文件工作流。旧 <code>.easy.api.config*</code> 文件仍会被读取以保持向后兼容。</li><li><strong>内置 AI 助手</strong> (<code>#1398</code>)——与供应商无关的 AI 服务（基于 LangChain4j），内嵌在 Rules 标签页的规则编写 agent。AI 设置已提升为独立的顶级标签页。</li><li><strong>Postman 环境同步</strong> (<code>#722</code>)——将 Postman 环境同步到 API Dashboard，可在端点详情面板内联编辑。</li><li><strong>日志规范</strong> (<code>#1393</code>、<code>#1394</code>、<code>#1396</code>)——EasyAPI 控制台默认 <code>SILENT</code>，当日志级别为 <code>SILENT</code> 时隐藏。插件失败时会显示自解释通知，而不是静默堆栈。</li><li><strong>AI key 存储</strong> (<code>#1403</code>)——AI 供应商密钥通过独立的 <code>AiApiKeyStore</code> 存储在 IntelliJ 的 <code>PasswordSafe</code> 中，不再以明文形式存于设置。</li></ul><p>完整发布说明请参见 <a href="https://github.com/tangcent/easy-yapi/blob/master/CHANGELOG.md" target="_blank" rel="noreferrer">changelog</a>。</p>`,43)])])}const u=e(i,[["render",d]]);export{g as __pageData,u as default};
